  ('social-worker-moex-05353', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '面對學齡前兒童與學齡兒童的各種攻擊、暴力的警訊與行為時，社會工作者建議父母、照顧者應有的處 遇原則，下列陳述何者較不適當？', '["進行行為管教技巧，並給予直接的訓誡", "進行不相容反應技巧，不理會攻擊行為", "進行暫停程序的技巧，將孩子從場所中移開", "進行角色楷模的策略，採用非攻擊性的衝突解決策略的楷模與導師"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
